import base64
import json

def confirmAuth(headers):
    token_str = headers.get('AuthToken', '')
    try:
        decoded = base64.b64decode(token_str)
    except (TypeError, ValueError):
        return None
    try:
        token_json = decoded.decode('utf-8')
        token = json.loads(token_json)
    except (UnicodeDecodeError, json.JSONDecodeError):
        return None
    if token.get('valid') and token.get('data'):
        return token['data']
    else:
        return None
